        ["algo" => 528, "uuid" => "ebc665", "name" => "schmivitz", "type" => "threshold", "status" => "active", "title" => "Schmivitz", "description_md" => "Schmivitz is a zero-knowledge threshold proof system enabling a threshold of parties to collectively produce ZK proofs without any individual learning the witness.", "mental_model" => "Threshold zero-knowledge proofs -- t-of-n parties produce ZK proof collectively.", "purpose" => ["threshold zk proofs"], "good_for" => ["multi-party zk proof generation"], "avoid_for" => ["single-prover zk (groth16/plonk)"], "pros" => ["threshold zk proofs", "no single witness holder"], "cons" => ["complex", "research scheme"], "difficulty" => 5, "security" => 4, "quantum_impact" => "Classical.", "post_quantum_status" => 1, "example" => ["scenario" => "3-of-5 threshold ZK proof", "input" => ["witness_shares" => "3-of-5", "statement" => "zk statement"], "output" => ["proof" => "threshold zk proof"]], "flow" => ["distribute witness via secret sharing", "each party computes partial proof", "combine proofs"], "related" => ["pvss", "frost", "groth16"]],
        ["algo" => 529, "uuid" => "90410c", "name" => "smallwood", "type" => "threshold", "status" => "active", "title" => "Smallwood", "description_md" => "Smallwood is an efficient small-scale MPC protocol optimized for 2-3 party scenarios with minimal communication rounds.", "mental_model" => "Optimized 2-3 party MPC -- minimal rounds for small-scale computation.", "purpose" => ["2-3 party mpc optimization"], "good_for" => ["2pc or 3pc mpc", "small party mpc"], "avoid_for" => ["large n parties (spdz/gmw)"], "pros" => ["minimal rounds 2-3 party", "efficient small n"], "cons" => ["not scalable to large n"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Classical.", "post_quantum_status" => 1, "example" => ["scenario" => "3-party Smallwood MPC", "input" => ["parties" => 3, "circuit" => "small"], "output" => ["result" => "3pc mpc result"]], "flow" => ["2-3 party optimized protocol", "constant round ot-based"], "related" => ["gmw", "spdz", "ot"]],
        ["algo" => 530, "uuid" => "18329c", "name" => "shamir", "type" => "threshold", "status" => "active", "title" => "Shamir Secret Sharing", "description_md" => "Shamir Secret Sharing (SSS) is the foundational t-of-n secret sharing scheme by Adi Shamir (1979). Uses polynomial interpolation: a degree-(t-1) polynomial with the secret at x=0 is evaluated at n points.\n\nShamir is the building block for virtually all threshold cryptography. t shares uniquely reconstruct the polynomial (and secret); fewer than t shares give zero information. Used in hardware wallets (e.g., Trezor SLIP39 mnemonics), Bitcoin SSSS, AWS CloudHSM, and all t-BLS/FROST key generation.", "mental_model" => "t-of-n polynomial secret sharing -- Shamir 1979, building block for all threshold crypto.", "purpose" => ["secret splitting t-of-n"], "good_for" => ["key backup splitting", "threshold crypto foundation", "hardware wallet slip39", "frost/tbls keygen"], "avoid_for" => ["active signing (needs frost/tbls)", "verifiable (feldman-vss or pedersen-vss)"], "pros" => ["information-theoretically secure", "simple polynomial math", "universal threshold building block"], "cons" => ["passive (no verification without vss)", "no active security alone"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Information-theoretic; quantum-secure.", "post_quantum_status" => 5, "example" => ["scenario" => "Trezor SLIP39 wallet seed splitting 3-of-5", "input" => ["secret" => "256-bit wallet seed", "t" => 3, "n" => 5], "output" => ["shares" => "5 mnemonics, any 3 recover seed"]], "flow" => ["pick random degree-(t-1) polynomial f(x) with f(0)=secret", "compute shares f(1)...f(n)", "recover: lagrange interpolation on t shares"], "related" => ["feldman-vss", "pedersen-vss", "dkg", "frost", "tbls"]],
        ["algo" => 531, "uuid" => "85dda2", "name" => "feldman-vss", "type" => "threshold", "status" => "active", "title" => "Feldman VSS", "description_md" => "Feldman VSS (Verifiable Secret Sharing) extends Shamir with public commitments to the polynomial coefficients, allowing share holders to verify their share without revealing the secret.\n\nFeldman VSS is used in virtually all practical threshold cryptography (FROST keygen, t-BLS, DKG). The dealer broadcasts commitments C_i = g^{a_i} to the polynomial coefficients, allowing each party to verify their share.", "mental_model" => "Verifiable Shamir -- polynomial commitments allow share verification without revealing secret.", "purpose" => ["verifiable secret sharing"], "good_for" => ["frost/tbls keygen", "dkg building block", "share verification"], "avoid_for" => ["information-theoretic (shamir)", "hiding dealer (pedersen-vss)"], "pros" => ["share verification", "dkg/frost standard component", "additive homomorphic"], "cons" => ["reveals dealing relationship in commitments"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DLP-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "FROST DKG using Feldman VSS", "input" => ["secret" => "priv scalar", "t" => 3, "n" => 5], "output" => ["shares" => "5 verified shares"]], "flow" => ["dealer: compute polynomial coefficients", "publish commitments g^a_0 ... g^a_{t-1}", "each party verifies share against commitments"], "related" => ["shamir", "pedersen-vss", "dkg", "frost"]],
        ["algo" => 532, "uuid" => "b33107", "name" => "pedersen-vss", "type" => "threshold", "status" => "active", "title" => "Pedersen VSS", "description_md" => "Pedersen VSS extends Feldman VSS with perfectly hiding commitments (Pedersen commitments with a blinding factor). The dealer's identity is hidden even from the commitment.\n\nPedersen VSS is used in DKG protocols (Pedersen DKG) where hiding the dealer's contribution from others is important. More secure than Feldman VSS in adversarial dealer scenarios.", "mental_model" => "Pedersen commitment VSS -- hides dealer in commitments, stronger than Feldman.", "purpose" => ["perfectly-hiding verifiable secret sharing"], "good_for" => ["pedersen dkg", "stronger dkg with hidden dealer"], "avoid_for" => ["simple vss (feldman simpler)"], "pros" => ["perfectly hiding commitments", "stronger security than feldman-vss"], "cons" => ["more complex than feldman-vss", "dlp-based quantum-vulnerable"], "difficulty" => 3, "security" => 5, "quantum_impact" => "DLP-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Pedersen DKG round", "input" => ["secret" => "priv scalar", "blinding" => "random"], "output" => ["shares" => "verified hidden shares"]], "flow" => ["pedersen commitment: C = g^s * h^r", "share verification with commitment", "combine: additive share aggregation"], "related" => ["feldman-vss", "shamir", "dkg"]],
        ["algo" => 533, "uuid" => "e5b09d", "name" => "dkg", "type" => "threshold", "status" => "active", "title" => "DKG", "description_md" => "DKG (Distributed Key Generation) allows a group of n parties to jointly generate a threshold key pair (public key + n shares of private key) without any single party ever knowing the full private key.\n\nDKG is used in FROST keygen, t-BLS setup, threshold ECDSA, blockchain validator key ceremonies, and MPC wallets. Pedersen DKG is the most common construction. After DKG, no party knows the private key -- only shares.", "mental_model" => "Distributed Key Generation -- nobody has the private key, only t-of-n shares. FROST/BLS setup.", "purpose" => ["joint key generation without trusted dealer"], "good_for" => ["frost keygen", "tbls setup", "threshold ecdsa setup", "blockchain key ceremony"], "avoid_for" => ["trusted dealer acceptable (feldman vss simpler)"], "pros" => ["no trusted dealer needed", "private key never exists in one place", "frost/bls/ecdsa standard"], "cons" => ["complex multi-round protocol", "abort handling needed for malicious parties"], "difficulty" => 4, "security" => 5, "quantum_impact" => "DLP-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum validator key ceremony DKG", "input" => ["parties" => 7, "threshold" => 5], "output" => ["pubkey" => "joint public key", "shares" => "7 private shares"]], "flow" => ["each party: feldman/pedersen vss of random value", "broadcast vss commitments", "each party: sum all received shares", "verify: sum commitments match joint pubkey"], "related" => ["feldman-vss", "pedersen-vss", "frost", "tbls", "async-dkg"]],
        ["algo" => 534, "uuid" => "00db4d", "name" => "pvss", "type" => "threshold", "status" => "active", "title" => "PVSS", "description_md" => "PVSS (Publicly Verifiable Secret Sharing) extends VSS so that anyone (not just share holders) can verify the correctness of shares without the secret.\n\nPVSS is used in commit-reveal protocols, random beacon generation (DRAND, Ethereum RANDAO), and blockchain public lotteries where public verifiability of sharing is required.", "mental_model" => "Publicly verifiable secret sharing -- anyone can verify shares, used in DRAND random beacon.", "purpose" => ["publicly verifiable secret sharing"], "good_for" => ["random beacon (drand)", "blockchain randao/lottery", "publicly verifiable ceremony"], "avoid_for" => ["private-only (feldman-vss)"], "pros" => ["public verifiability", "blockchain beacon standard", "transparent ceremony"], "cons" => ["reveals more info than feldman-vss", "dlp-based"], "difficulty" => 3, "security" => 4, "quantum_impact" => "DLP-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "DRAND random beacon round", "input" => ["participants" => 7, "round" => 12345], "output" => ["random" => "publicly verifiable random output"]], "flow" => ["each party pvss shares a random value", "anyone verifies shares", "threshold reconstruct to produce randomness"], "related" => ["feldman-vss", "dkg", "frost"]],
        ["algo" => 535, "uuid" => "c451de", "name" => "ot", "type" => "threshold", "status" => "active", "title" => "Oblivious Transfer", "description_md" => "OT (Oblivious Transfer) is a fundamental MPC building block where a sender sends one of n messages but doesn't know which one the receiver got, and the receiver learns only one message.\n\n1-of-2 OT is the most common form (sender has m_0 and m_1; receiver gets m_b without sender knowing b). OT is the cornerstone primitive for garbled circuits (GMW, Yao), VOLE, MASCOT, and almost all practical MPC protocols.", "mental_model" => "1-of-2 OT -- sender has 2 messages, receiver gets 1, sender doesn't know which. MPC building block.", "purpose" => ["mpc oblivious transfer primitive"], "good_for" => ["mpc building block", "garbled circuit input", "vole/mascot base"], "avoid_for" => ["standalone use (always MPC component)"], "pros" => ["information-theoretically secure with OT extension", "universal MPC primitive", "ot extension efficient"], "cons" => ["abstract primitive, not standalone", "ot extension cost"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Classical OT quantum-vulnerable; PQ-OT exists.", "post_quantum_status" => 2, "example" => ["scenario" => "1-of-2 OT in garbled circuit", "input" => ["sender" => "(m_0, m_1)", "receiver" => "choice bit b"], "output" => ["receiver_gets" => "m_b", "sender_knows" => "nothing about b"]], "flow" => ["ot base from public key ops", "ot extension for bulk ot", "input labels for garbled circuit"], "related" => ["gmw", "spdz", "beaver", "vole"]],
        ["algo" => 536, "uuid" => "718acd", "name" => "vole", "type" => "threshold", "status" => "active", "title" => "VOLE", "description_md" => "VOLE (Vector OLE -- Oblivious Linear-function Evaluation) is an MPC primitive where one party evaluates ax+b obliviously. VOLE enables efficient zero-knowledge proofs (VOLE-ZK) and MPC.\n\nVOLE is used in modern ZK proof systems (Mac'n'Cheese, QuickSilver, FAEST post-quantum signature). VOLE-based ZK is the most efficient known ZK for large circuits.", "mental_model" => "Oblivious linear function evaluation -- foundation for VOLE-ZK and modern efficient ZK proofs.", "purpose" => ["vole mpc primitive and vole-zk"], "good_for" => ["vole-zk large circuit proofs", "mpc building block", "faest pq signature"], "avoid_for" => ["simple zk (groth16/plonk for snark)"], "pros" => ["most efficient large-circuit zk", "vole-zk linear prover", "faest pq sig uses vole"], "cons" => ["less succinct than snark proofs"], "difficulty" => 4, "security" => 5, "quantum_impact" => "VOLE-ZK can be made PQ.", "post_quantum_status" => 4, "example" => ["scenario" => "VOLE-ZK large circuit proof", "input" => ["prover" => "witness w", "circuit" => "C(x,w)=true"], "output" => ["proof" => "vole-zk proof"]], "flow" => ["setup vole correlations via ot extension", "prover sends masked witness", "verifier checks via vole correlations"], "related" => ["ot", "spdz", "beaver"]],
        ["algo" => 537, "uuid" => "cd5a7e", "name" => "beaver", "type" => "threshold", "status" => "active", "title" => "Beaver Triples", "description_md" => "Beaver multiplication triples (a,b,c) with c=a*b are the core offline-phase output for SPDZ and many MPC protocols. Parties hold shares of (a,b,c=ab) -- using them allows an online multiplication with low communication.\n\nBeaver triples are the key innovation of SPDZ-family MPC. They are pre-computed in an offline phase and consumed during the online phase for each multiplication gate.", "mental_model" => "Offline multiplication triple (a,b,c=ab) -- SPDZ core primitive, offline/online MPC split.", "purpose" => ["mpc multiplication triple"], "good_for" => ["spdz mpc multiplication gates", "offline phase mpc"], "avoid_for" => ["standalone (MPC component)"], "pros" => ["low-communication online multiplication", "spdz standard", "offline pre-compute separation"], "cons" => ["triples consumed on use", "offline generation cost"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Classical (PQ variants exist).", "post_quantum_status" => 2, "example" => ["scenario" => "SPDZ online multiplication gate", "input" => ["x_share" => "share of x", "y_share" => "share of y", "beaver" => "(a,b,ab shares)"], "output" => ["z_share" => "share of x*y"]], "flow" => ["offline: generate (a,b,ab) beaver triple", "online: parties reveal (x-a) and (y-b)", "compute z = (x-a)(y-b) + a(y-b) + b(x-a) + ab"], "related" => ["spdz", "mascot", "vole"]],
        ["algo" => 538, "uuid" => "3bad49", "name" => "mpc-ecdsa", "type" => "threshold", "status" => "active", "title" => "MPC-ECDSA", "description_md" => "MPC-ECDSA is threshold ECDSA realized through multi-party computation. Produces standard ECDSA signatures with no trusted dealer.\n\nMPC-ECDSA is used in crypto custody (Fireblocks, Qredo), MPC wallets (ZenGo), and exchange cold storage. The GG20/GG21 protocols are the most deployed. Avoids needing Schnorr/BLS by enabling threshold ECDSA without changing the signature format.", "mental_model" => "Threshold ECDSA via MPC -- Fireblocks/Zengo custody wallets, standard ECDSA output.", "purpose" => ["threshold ecdsa mpc signing"], "good_for" => ["crypto custody threshold ecdsa", "mpc wallet", "exchange cold storage"], "avoid_for" => ["schnorr (frost simpler)", "post-quantum signing"], "pros" => ["standard ecdsa output", "no signature format change", "fireblocks/zengo standard"], "cons" => ["complex mpc", "ecdsa quantum-vulnerable", "gg18 broken (use gg20+)"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Fireblocks 2-of-3 threshold ECDSA custody", "input" => ["threshold" => 2, "parties" => 3, "tx" => "bitcoin tx hash"], "output" => ["sig" => "standard ECDSA signature"]], "flow" => ["dkg: generate ecdsa key without any party knowing priv", "online: gg20/21 interactive signing protocol", "output: standard ecdsa (r,s)"], "related" => ["gg20", "gg21", "cmp", "frost", "dkg"]],
        ["algo" => 539, "uuid" => "fd272e", "name" => "mpc-schnorr", "type" => "threshold", "status" => "active", "title" => "MPC-Schnorr", "description_md" => "MPC-Schnorr is threshold Schnorr via multi-party computation. Subsumes FROST and classic threshold Schnorr with MPC security analysis.\n\nMPC-Schnorr produces standard Schnorr signatures. FROST is the most practical deployed MPC-Schnorr. Used in blockchain threshold signing, DEX governance, and Zcash threshold.", "mental_model" => "Threshold Schnorr via MPC -- general term encompassing FROST. Standard Schnorr output.", "purpose" => ["threshold schnorr mpc"], "good_for" => ["threshold schnorr (see frost for practical)"], "avoid_for" => ["production (use frost specifically)"], "pros" => ["standard schnorr output", "mpc security analysis"], "cons" => ["frost is the specific standard"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Schnorr quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Threshold Schnorr via MPC", "input" => ["threshold" => 3, "parties" => 5], "output" => ["sig" => "standard schnorr sig"]], "flow" => ["same as frost protocol flow"], "related" => ["frost", "mpc-ecdsa", "musig2"]],
    ],
    "legacy" => [
        ["algo" => 540, "uuid" => "a34a97", "name" => "roast", "type" => "threshold", "status" => "legacy", "title" => "ROAST", "description_md" => "ROAST (Robust Asynchronous Schnorr Threshold) was an early robust threshold Schnorr protocol that handles malicious or aborting parties. Superseded by more efficient robust variants of FROST.\n\nROAST introduced the robustness concept for threshold Schnorr (completing even if some parties abort). Its ideas influenced later FROST variants but ROAST itself is superseded.", "mental_model" => "Early robust threshold Schnorr -- FROST with robustness, superseded by better FROST variants.", "purpose" => ["historical robust threshold schnorr"], "good_for" => ["threshold schnorr history study"], "avoid_for" => ["production (use frost)"], "pros" => ["introduced robustness for threshold schnorr"], "cons" => ["superseded by frost improvements"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Schnorr quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "ROAST robust threshold Schnorr", "input" => ["threshold" => "t-of-n"], "output" => ["sig" => "schnorr even with aborts"]], "flow" => ["subset selection to tolerate aborts", "multiple parallel signing sessions"], "related" => ["frost", "mpc-schnorr"]],
    ],
    "new" => [
        ["algo" => 541, "uuid" => "5ed40f", "name" => "gg18", "type" => "threshold", "status" => "new", "title" => "GG18 (BROKEN)", "description_md" => "GG18 is the first widely deployed threshold ECDSA protocol by Gennaro and Goldfeder (2018). Widely deployed in crypto wallets and custody. However, security vulnerabilities were found -- GG18 is susceptible to malicious party attacks.\n\nGG18 was the first practical t-of-n threshold ECDSA. Widely deployed but has known security issues. Replaced by GG20. Do not use GG18 in new deployments.", "mental_model" => "GG18 threshold ECDSA -- first widely deployed, known vulnerabilities, use GG20/GG21.", "purpose" => ["historical threshold ecdsa"], "good_for" => ["legacy gg18 compatibility"], "avoid_for" => ["any new deployment (gg20/gg21/cmp instead)"], "pros" => ["first t-of-n ecdsa standard"], "cons" => ["known security vulnerabilities", "replaced by gg20", "malicious party attacks"], "difficulty" => 4, "security" => 2, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "GG18 legacy wallet (migrate to GG20)", "input" => ["note" => "has known vulnerabilities"], "output" => ["warning" => "upgrade to GG20/GG21"]], "flow" => ["gg18 3-round threshold ecdsa"], "related" => ["gg20", "gg21", "cmp", "mpc-ecdsa"]],
        ["algo" => 542, "uuid" => "e49c59", "name" => "gg20", "type" => "threshold", "status" => "new", "title" => "GG20", "description_md" => "GG20 is the patched successor to GG18 by Gennaro and Goldfeder (2020) fixing the security vulnerabilities. The most widely deployed threshold ECDSA protocol.\n\nGG20 is deployed in Fireblocks, ZenGo, and most crypto custody platforms. Provides identifiable abort (if a party misbehaves, they can be identified). Still quantum-vulnerable but the current industry standard for threshold ECDSA.", "mental_model" => "GG20 threshold ECDSA -- industry standard, Fireblocks/ZenGo, identifiable abort, fixes GG18.", "purpose" => ["industry-standard threshold ecdsa"], "good_for" => ["crypto custody threshold ecdsa", "fireblocks-compatible mpc wallet"], "avoid_for" => ["schnorr threshold (frost simpler)", "post-quantum signing"], "pros" => ["fixes gg18 vulnerabilities", "identifiable abort", "industry standard", "fireblocks"], "cons" => ["ecdsa quantum-vulnerable", "3-round protocol"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "GG20 2-of-3 threshold ECDSA", "input" => ["threshold" => 2, "parties" => 3], "output" => ["sig" => "standard ECDSA"]], "flow" => ["round 1: commitments", "round 2: paillier-based mta protocol", "round 3: signature assembly"], "related" => ["gg21", "cmp", "gg18", "mpc-ecdsa"]],
        ["algo" => 543, "uuid" => "52df31", "name" => "gg21", "type" => "threshold", "status" => "new", "title" => "GG21", "description_md" => "GG21 improves GG20 with better efficiency and security proofs. Further reduces rounds and overhead for threshold ECDSA.\n\nGG21 is the latest iteration of the Gennaro-Goldfeder threshold ECDSA line. Some platforms have upgraded from GG20 to GG21.", "mental_model" => "GG21 improved threshold ECDSA -- more efficient than GG20.", "purpose" => ["improved threshold ecdsa"], "good_for" => ["newer threshold ecdsa deployment"], "avoid_for" => ["schnorr threshold (frost)"], "pros" => ["more efficient than gg20", "improved security proofs"], "cons" => ["ecdsa quantum-vulnerable", "cmp also competitive"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "GG21 threshold ECDSA", "input" => ["threshold" => "t-of-n"], "output" => ["sig" => "ecdsa"]], "flow" => ["improved gg20 round structure"], "related" => ["gg20", "cmp", "mpc-ecdsa"]],
        ["algo" => 544, "uuid" => "1928d8", "name" => "cmp", "type" => "threshold", "status" => "new", "title" => "CMP", "description_md" => "CMP (CGGMP21) is a threshold ECDSA protocol by Canetti, Gennaro, Goldfeder, Makriyannis, Peled (2021). Provides the strongest security model for threshold ECDSA with identifiable abort in the UC (Universally Composable) model.\n\nCMP is considered the most secure threshold ECDSA protocol. Implemented in tss-lib (Binance), Silence Laboratories, and other custody platforms.", "mental_model" => "CGGMP21 threshold ECDSA -- strongest security model (UC), identifiable abort. tss-lib standard.", "purpose" => ["strongest threshold ecdsa"], "good_for" => ["highest security threshold ecdsa", "uc-secure custody", "binance tss-lib"], "avoid_for" => ["schnorr threshold (frost simpler)"], "pros" => ["uc-secure", "identifiable abort", "strongest security model", "tss-lib"], "cons" => ["ecdsa quantum-vulnerable", "complex protocol"], "difficulty" => 4, "security" => 5, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "CMP UC-secure threshold ECDSA", "input" => ["threshold" => 3, "parties" => 5], "output" => ["sig" => "ecdsa (uc-secure)"]], "flow" => ["uc-secure threshold ecdsa", "identifiable abort mechanism", "paillier-based multiplication"], "related" => ["gg20", "gg21", "mpc-ecdsa", "dkg"]],
        ["algo" => 545, "uuid" => "aa9d8e", "name" => "lindell17", "type" => "threshold", "status" => "new", "title" => "Lindell17", "description_md" => "Lindell17 is a fast 2-party ECDSA protocol by Yehuda Lindell (2017). Specifically optimized for 2-of-2 threshold ECDSA -- faster than general n-party protocols.\n\nLindell17 is widely used in 2-party hardware/software wallet setups (device + server). Faster than GG20 for the specific 2-of-2 case.", "mental_model" => "2-party ECDSA -- faster 2-of-2 threshold, device+server wallet standard.", "purpose" => ["2-of-2 threshold ecdsa"], "good_for" => ["2-of-2 device+server wallet", "fast 2pc ecdsa"], "avoid_for" => ["t>2 threshold (gg20/cmp)"], "pros" => ["fastest 2-of-2 ecdsa", "device+server wallet standard"], "cons" => ["only 2-party (not general t-of-n)", "ecdsa quantum-vulnerable"], "difficulty" => 3, "security" => 4, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Lindell17 2-of-2 mobile wallet", "input" => ["device_share" => "priv share 1", "server_share" => "priv share 2"], "output" => ["sig" => "ecdsa"]], "flow" => ["2pc ecdsa: paillier-based lindell17 protocol", "2 rounds only for 2-party case"], "related" => ["gg20", "cmp", "amber", "mpc-ecdsa"]],
        ["algo" => 546, "uuid" => "600dfb", "name" => "doerner-shelat", "type" => "threshold", "status" => "new", "title" => "Doerner-Shelat", "description_md" => "Doerner-Shelat is a 2-party ECDSA protocol based on OT extension (rather than Paillier encryption like Lindell17). Provides competitive performance for 2-of-2 threshold ECDSA.", "mental_model" => "OT-based 2-party ECDSA -- Paillier-free 2PC ECDSA via OT extension.", "purpose" => ["ot-based 2-of-2 ecdsa"], "good_for" => ["paillier-free 2pc ecdsa"], "avoid_for" => ["t>2 threshold", "paillier-ok (lindell17 simpler)"], "pros" => ["no paillier needed", "ot-extension based", "2-party efficient"], "cons" => ["2-party only", "ecdsa quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ECDSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Doerner-Shelat 2PC ECDSA", "input" => ["party1" => "key share 1", "party2" => "key share 2"], "output" => ["sig" => "ecdsa"]], "flow" => ["ot extension based multiplication in signing", "2-round protocol"], "related" => ["lindell17", "gg20", "ot"]],
        ["algo" => 547, "uuid" => "e2286d", "name" => "spdz", "type" => "threshold", "status" => "new", "title" => "SPDZ", "description_md" => "SPDZ (Speedz, pronounced 'speedzee') is a practically efficient MPC protocol for arbitrary computation with malicious security. Uses Beaver triples and MACs for authenticated secret sharing.\n\nSPDZ is the most deployed general-purpose MPC framework (used in SCALE-MAMBA, MP-SPDZ). Provides malicious security with abort. Split into offline phase (Beaver triple generation via OT) and fast online phase.", "mental_model" => "SPDZ general-purpose maliciously-secure MPC -- industry standard, MP-SPDZ framework.", "purpose" => ["general purpose malicious mpc"], "good_for" => ["arbitrary mpc computation", "mp-spdz framework", "privacy-preserving analytics"], "avoid_for" => ["simple threshold signing (frost/tbls)"], "pros" => ["malicious security", "general arbitrary computation", "mp-spdz standard", "offline/online split"], "cons" => ["offline phase overhead", "complex setup"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Classical (PQ SPDZ variants in research).", "post_quantum_status" => 2, "example" => ["scenario" => "SPDZ private ML model inference", "input" => ["encrypted_model" => "shares", "encrypted_input" => "shares"], "output" => ["result" => "inference result (privacy-preserving)"]], "flow" => ["offline: generate beaver triples via ot", "online: arithmetic circuit eval with mac verification", "output extraction: reconstruct result"], "related" => ["mascot", "beaver", "gmw", "vole"]],
        ["algo" => 548, "uuid" => "038e72", "name" => "mascot", "type" => "threshold", "status" => "new", "title" => "MASCOT", "description_md" => "MASCOT (Faster Malicious Arithmetic Secure Computation with Oblivious Transfer) is an efficient offline phase protocol for SPDZ that generates Beaver triples using OT extension.\n\nMASCOT replaces expensive homomorphic encryption (BGV/SPDZ offline) with efficient OT-based Beaver triple generation. Used in MP-SPDZ as the default offline phase.", "mental_model" => "OT-based Beaver triple generation -- replaces FHE offline phase in SPDZ, MP-SPDZ default.", "purpose" => ["ot-based spdz offline phase"], "good_for" => ["spdz offline phase", "mp-spdz mascot mode"], "avoid_for" => ["online mpc phase (spdz/gmw)"], "pros" => ["faster than fhe-based offline", "ot-extension efficient", "mp-spdz standard"], "cons" => ["offline only component", "complex"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Classical.", "post_quantum_status" => 2, "example" => ["scenario" => "MASCOT Beaver triple generation for SPDZ", "input" => ["parties" => 3, "triples_needed" => 1000000], "output" => ["beaver_triples" => "1M authenticated triples"]], "flow" => ["base OT setup", "OT extension for correlation", "triple check and sacrifice"], "related" => ["spdz", "beaver", "ot", "vole"]],
        ["algo" => 549, "uuid" => "34cd96", "name" => "bmr", "type" => "threshold", "status" => "new", "title" => "BMR", "description_md" => "BMR (Beaver-Micali-Rogaway) is a multi-party garbled circuit protocol for constant-round MPC. Extends Yao's 2-party garbled circuits to n parties.\n\nBMR enables n-party garbled circuit evaluation with constant communication rounds. Used in protocols requiring constant-round n-party computation.", "mental_model" => "n-party garbled circuit -- Yao extended to n parties, constant rounds.", "purpose" => ["n-party garbled circuit mpc"], "good_for" => ["constant-round n-party mpc", "garbled circuit n-party"], "avoid_for" => ["2-party (yao simpler)", "large n (spdz better)"], "pros" => ["constant communication rounds", "n-party generalization of yao"], "cons" => ["large communication (garbled circuit size)"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Classical.", "post_quantum_status" => 2, "example" => ["scenario" => "BMR 4-party constant-round MPC", "input" => ["parties" => 4, "circuit" => "boolean circuit"], "output" => ["result" => "circuit output"]], "flow" => ["parties jointly garble circuit", "each party has key shares in garbled wires", "evaluate garbled circuit collectively"], "related" => ["gmw", "spdz", "ot"]],
        ["algo" => 550, "uuid" => "1ec745", "name" => "gmw", "type" => "threshold", "status" => "new", "title" => "GMW", "description_md" => "GMW (Goldreich-Micali-Wigderson) is the foundational protocol for multi-party computation of boolean circuits. Uses OT for AND gate computation; XOR is free.\n\nGMW proved that any function can be computed securely with semi-honest security. The foundation for much of MPC theory. Less efficient than SPDZ but simpler and foundational.", "mental_model" => "Foundational multi-party boolean circuit evaluation -- GMW 1987, XOR-free AND via OT.", "purpose" => ["foundational n-party boolean mpc"], "good_for" => ["boolean circuit mpc", "mpc theory foundation", "ccgmp/bmr variants"], "avoid_for" => ["arithmetic (spdz)", "performance-critical (spdz faster)"], "pros" => ["foundational mpc protocol", "information-theoretically secure AND via OT", "any circuit"], "cons" => ["many rounds for deep circuits", "spdz faster for arithmetic"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Classical.", "post_quantum_status" => 2, "example" => ["scenario" => "GMW private set intersection", "input" => ["alice_set" => "{a,b,c}", "bob_set" => "{b,c,d}"], "output" => ["intersection" => "{b,c} (neither learns other's set)"]], "flow" => ["xor gates: free (additive shares)", "and gates: 2pc OT per AND", "reconstruct output shares"], "related" => ["spdz", "bmr", "ot", "beaver"]],
        ["algo" => 551, "uuid" => "0f7fbd", "name" => "proactive-ss", "type" => "threshold", "status" => "new", "title" => "Proactive Secret Sharing", "description_md" => "Proactive Secret Sharing (PSS) periodically refreshes secret shares without changing the secret or public key. Defends against a mobile adversary that compromises t parties within each time window.\n\nPSS is used in long-lived threshold systems where gradual compromise is a threat -- HSM clusters, threshold CAs, long-term key custody.", "mental_model" => "Periodic share refresh -- defend mobile adversary, each window can compromise at most t-1 parties.", "purpose" => ["proactive mobile-adversary defense"], "good_for" => ["long-term threshold custody", "hsm cluster proactive security", "threshold ca"], "avoid_for" => ["short-lived keys (overhead not worth it)"], "pros" => ["mobile adversary defense", "gradual compromise protection", "no pubkey change"], "cons" => ["refresh protocol coordination overhead", "complex"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Classical (PQ variants possible).", "post_quantum_status" => 2, "example" => ["scenario" => "Threshold CA monthly share refresh", "input" => ["old_shares" => "t-of-n shares"], "output" => ["new_shares" => "refreshed shares, same pubkey"]], "flow" => ["epoch boundary: all parties run refresh subprotocol", "each party adds random re-sharing of 0", "new shares are functionally equivalent"], "related" => ["shamir", "pantheria", "redeta", "dkg"]],
        ["algo" => 552, "uuid" => "eaf137", "name" => "async-dkg", "type" => "threshold", "status" => "new", "title" => "Async DKG", "description_md" => "Asynchronous DKG (ADKG) performs distributed key generation in asynchronous networks where message delivery is not guaranteed to be timely.\n\nADKG is used in blockchain consensus (HotStuff, DFINITY/IC), Byzantine fault tolerant systems, and any DKG that cannot assume synchrony.", "mental_model" => "Asynchronous distributed key generation -- Byzantine/BFT networks without timing assumptions.", "purpose" => ["async byzantine-tolerant dkg"], "good_for" => ["blockchain bft dkg", "async threshold key gen", "ic/dfinity style"], "avoid_for" => ["synchronous networks (standard dkg simpler)"], "pros" => ["async tolerant", "byzantine fault tolerant", "blockchain consensus"], "cons" => ["complex async proofs", "higher overhead than sync dkg"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Classical (DLP-based).", "post_quantum_status" => 1, "example" => ["scenario" => "DFINITY Internet Computer ADKG", "input" => ["parties" => "IC nodes", "threshold" => "BFT threshold"], "output" => ["pubkey" => "joint key", "shares" => "node shares"]], "flow" => ["async reliable broadcast", "async complete secret sharing (acss)", "combine to DKG output"], "related" => ["dkg", "frost", "pvss"]],
        ["algo" => 553, "uuid" => "c415da", "name" => "robust-dkg", "type" => "threshold", "status" => "new", "title" => "Robust DKG", "description_md" => "Robust DKG completes successfully even if some parties abort or behave maliciously (within the honest majority). Standard DKG may abort if any party misbehaves.\n\nRobust DKG is critical for blockchain-based threshold key ceremonies where nodes may drop out.", "mental_model" => "DKG that completes despite party aborts -- blockchain node drop-out tolerance.", "purpose" => ["abort-tolerant dkg"], "good_for" => ["blockchain threshold dkg with dropout", "abort-tolerant key ceremony"], "avoid_for" => ["trusted setting (standard dkg simpler)"], "pros" => ["robust to aborts", "completes despite malicious parties", "blockchain-suitable"], "cons" => ["more complex than standard dkg", "identification overhead"], "difficulty" => 5, "security" => 5, "quantum_impact" => "Classical.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum validator robust DKG", "input" => ["parties" => 7, "threshold" => 5, "max_malicious" => 2], "output" => ["pubkey" => "joint key despite 2 aborts"]], "flow" => ["run vss from all parties", "discard VSS of misbehaving parties", "aggregate remaining to joint key"], "related" => ["dkg", "async-dkg", "feldman-vss"]],
        ["algo" => 554, "uuid" => "5aee0b", "name" => "ring-sig-generic", "type" => "threshold", "status" => "new", "title" => "Ring Signature (Generic)", "description_md" => "Generic ring signatures allow a signer to produce a signature that could have come from any member of a specified ring, without revealing which member signed.\n\nRing signatures generalize group signatures without a manager. Used in Monero (cryptonote), privacy-preserving whistleblowing, and anonymous authentication. The signer self-selects the ring.", "mental_model" => "Generic ring signature framework -- signer picks ring, anonymity within ring. Monero-style.", "purpose" => ["generic ring anonymity"], "good_for" => ["anonymous signing within ad-hoc ring", "privacy ring protocols"], "avoid_for" => ["accountability needed (group sig)", "threshold efficiency (frost)"], "pros" => ["self-select ring (no manager)", "anonymity within ring", "monero-compatible"], "cons" => ["sig size scales with ring", "quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "EC-based quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Anonymous whistleblower in 100-member org", "input" => ["ring" => "100 org pubkeys", "message" => "disclosure"], "output" => ["ring_sig" => "anonymous sig"]], "flow" => ["signer picks ring R containing their key", "compute ring sig (all members linked)", "verify: one of ring members signed"], "related" => ["cryptonote-ring-sig", "linkable-ring-sig", "group-sig"]],
        ["algo" => 555, "uuid" => "168bc1", "name" => "linkable-ring-sig", "type" => "threshold", "status" => "new", "title" => "Linkable Ring Sig", "description_md" => "Linkable Ring Signatures (LRS) extend ring signatures with a 'key image' that is unique per signer -- if the same private key signs twice, the key images will match, revealing double-use.\n\nLinkable ring signatures are the core primitive in Monero (CryptoNote protocol). Key images prevent double-spending while maintaining signer anonymity.", "mental_model" => "Ring signature + key image -- double-spend detection while preserving anonymity. Monero core.", "purpose" => ["anonymous ring sig with double-spend detection"], "good_for" => ["monero-style double-spend prevention", "anonymous crypto with key image"], "avoid_for" => ["unconditional anonymity (generic ring sig)"], "pros" => ["double-spend detection via key image", "monero standard", "signer anonymity maintained"], "cons" => ["key image reveals re-use", "ec quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "EC quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Monero linkable ring sig double-spend check", "input" => ["ring" => "decoys + signer", "key_image" => "unique per priv key"], "output" => ["sig" => "linkable ring sig with key image"]], "flow" => ["compute key image I = priv * H_p(pubkey)", "ring sig with I embedded", "verify: I unique -> no double spend"], "related" => ["cryptonote-ring-sig", "ring-sig-generic", "clsag"]],
